import{_ as a,o as t,c as i,a3 as o}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse(`{"title":"E School Based Apprentices","description":"","frontmatter":{"title":"E School Based Apprentices","eba":"Children's Services Award 2010","topics":["schedules","wages","apprentices"]},"headers":[],"relativePath":"ebas/childrens-services/schedules/e-school-based-apprentices.md","filePath":"ebas/childrens-services/schedules/e-school-based-apprentices.md"}`),r={name:"ebas/childrens-services/schedules/e-school-based-apprentices.md"};function s(n,e,p,c,l,d){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="e-school-based-apprentices" tabindex="-1">E School Based Apprentices <a class="header-anchor" href="#e-school-based-apprentices" aria-label="Permalink to &quot;E School Based Apprentices&quot;">​</a></h1><ol><li><p>This schedule applies to school-based apprentices. A school-based apprentice is a person who is undertaking an apprenticeship in accordance with this schedule while also undertaking a course of secondary education.</p></li><li><p>A school-based apprenticeship may be undertaken in the trades covered by this award under a training agreement or contract of training for an apprentice declared or recognised by the relevant State or Territory authority.</p></li><li><p>The relevant minimum wages for full-time junior and adult apprentices provided for in this award, calculated hourly, will apply to school-based apprentices for total hours worked including time deemed to be spent in off-the-job training.</p></li><li><p>For the purposes of E.3, where an apprentice is a full-time school student, the time spent in off-the-job training for which the apprentice must be paid is 25% of the actual hours worked each week on-the-job. The wages paid for training time may be averaged over the semester or year.</p></li><li><p>A school-based apprentice must be allowed, over the duration of the apprenticeship, the same amount of time to attend off-the-job training as an equivalent full-time apprentice.</p></li><li><p>For the purposes of this schedule, off-the-job training is structured training delivered by a Registered Training Organisation separate from normal work duties or general supervised practice undertaken on the job.</p></li><li><p>The duration of the apprenticeship must be as specified in the training agreement or contract for each apprentice but must not exceed six years.</p></li><li><p>School-based apprentices progress through the relevant wage scale at the rate of 12 months progression or the rate of competency-based progression for each two years of employment as an apprentice or at the rate of competency-based progression if provided for in this award.</p></li><li><p>The apprentice wage scales are based on a standard full-time apprenticeship of four years (unless the apprenticeship is of three years duration) or stages of competency based progression (if provided for in this award). The rate of progression reflects the average rate of skill acquisition expected from the typical combination of work and training for a school-based apprentice undertaking the applicable apprenticeship.</p></li><li><p>If an apprentice converts from school-based to full-time, the successful completion of competencies (if provided for in this award) and all time spent as a full-time apprentice will count for the purposes of progression through the relevant wage scale in addition to the progression achieved as a school-based apprentice.</p></li><li><p>School-based apprentices are entitled pro rata to all of the other conditions in this award.</p></li></ol>',2)])])}const u=a(r,[["render",s]]);export{f as __pageData,u as default};
